from typing import List, Tuple

def daddress(t: Tuple) -> Tuple[str, any]:
    return ("daddress", t[0])

def dcommand(t: Tuple) -> Tuple[str, str]:
    return ("dcommand", str(t[0]))

def doaddress(t: any) -> Tuple[str, any]:
    return ("doaddress", t)

def dosymbol(t: any) -> Tuple[str, str]:
    return ("dosymbol", str(t))

def process_tuples(tuples: List[Tuple]) -> List[Tuple]:
    result = []
    for t in tuples:
        if isinstance(t, tuple):
            if len(t) == 1:
                result.append(doaddress(t[0]))
            elif len(t) == 2:
                result.append(daddress(t))
        else:
            result.append(dosymbol(t))
    return result
